import numpy as np

def update_edge_distance(edge_distance: np.ndarray, local_opt_tour: np.ndarray,
                          edge_n_used: np.ndarray) -> np.ndarray:
    updated = edge_distance.copy()
    n = len(local_opt_tour)

    # Build set of tour edges
    tour_edges = set()
    for i in range(n):
        u = local_opt_tour[i]
        v = local_opt_tour[(i + 1) % n]
        if u < v:
            tour_edges.add((u, v))
        else:
            tour_edges.add((v, u))

    max_dist = edge_distance.max()
    decay_base = 0.8
    perturbation_scale = 0.05 * max_dist

    for i in range(n):
        for j in range(i + 1, n):
            if (i, j) in tour_edges:
                # Multiplicative decay for tour edges
                factor = decay_base ** (1 + edge_n_used[i, j])
                updated[i, j] = edge_distance[i, j] * factor
                updated[j, i] = updated[i, j]
            else:
                # Perturbation for non-tour edges, scaled inversely by usage
                if edge_n_used[i, j] == 0:
                    perturbation = perturbation_scale * np.random.uniform(0.5, 1.5)
                else:
                    perturbation = perturbation_scale / (1 + edge_n_used[i, j])
                updated[i, j] = edge_distance[i, j] + perturbation
                updated[j, i] = updated[i, j]

    return updated

