def update_edge_distance(edge_distance: np.ndarray, local_opt_tour: np.ndarray,
                          edge_n_used: np.ndarray) -> np.ndarray:
    updated = edge_distance.copy()
    n = len(local_opt_tour)
    rng = np.random.default_rng()

    # Build list of tour edges (with closing edge)
    tour_edges = [(local_opt_tour[i], local_opt_tour[(i + 1) % n]) for i in range(n)]

    # Compute usage for each tour edge
    tour_usage = np.array([edge_n_used[u, v] for u, v in tour_edges])
    mean_usage = np.mean(tour_usage)

    # Identify clusters: contiguous segments where usage > mean_usage
    clusters = []
    i = 0
    while i < n:
        if tour_usage[i] > mean_usage:
            start = i
            while i < n and tour_usage[i] > mean_usage:
                i += 1
            clusters.append((start, i - 1))
        else:
            i += 1

    # Penalize edges inside clusters
    for start, end in clusters:
        cluster_size = end - start + 1
        if cluster_size < 2:
            continue
        # Penalty factor: proportional to average usage density in cluster
        cluster_usage_sum = np.sum(tour_usage[start:end+1])
        penalty_factor = 0.3 * (cluster_usage_sum / cluster_size)
        for idx in range(start, end + 1):
            u, v = tour_edges[idx]
            penalty = penalty_factor * edge_distance[u, v]
            updated[u, v] += penalty
            updated[v, u] += penalty

    # Reduce cost of edges that connect nodes from different clusters (inter-cluster jumps)
    if len(clusters) >= 2:
        # Collect nodes belonging to each cluster
        cluster_nodes = []
        for start, end in clusters:
            nodes = set()
            for idx in range(start, end + 1):
                nodes.add(local_opt_tour[idx])
            cluster_nodes.append(nodes)

        # Pick random inter-cluster node pairs that are not tour edges
        for a in range(len(clusters)):
            for b in range(a + 1, len(clusters)):
                candidates = []
                for u in cluster_nodes[a]:
                    for v in cluster_nodes[b]:
                        if (u, v) not in tour_edges and (v, u) not in tour_edges:
                            candidates.append((u, v))
                if candidates:
                    num_to_reduce = min(2, len(candidates))
                    chosen = rng.choice(len(candidates), size=num_to_reduce, replace=False)
                    for idx in chosen:
                        u, v = candidates[idx]
                        reduction = 0.2 * edge_distance[u, v]
                        updated[u, v] = max(0.1, updated[u, v] - reduction)
                        updated[v, u] = max(0.1, updated[v, u] - reduction)

    return updated

def update_edge_distance(edge_distance: np.ndarray, local_opt_tour: np.ndarray,
                          edge_n_used: np.ndarray) -> np.ndarray:
    updated = edge_distance.copy()
    n = len(local_opt_tour)
    rng = np.random.default_rng()

    idx1 = rng.integers(0, n)
    idx2 = rng.integers(0, n)
    while abs(idx1 - idx2) % n <= 1 or abs(idx1 - idx2) % n >= n - 1:
        idx2 = rng.integers(0, n)
    if idx1 > idx2:
        idx1, idx2 = idx2, idx1

    tour = local_opt_tour
    cut_nodes = set()
    for i in range(idx1, idx2 + 1):
        cut_nodes.add(tour[i])
    for i in range(idx2 + 1, n):
        cut_nodes.add(tour[i])
    for i in range(0, idx1):
        cut_nodes.add(tour[i])

    for i in range(n):
        for j in range(i + 1, n):
            u, v = tour[i], tour[j]
            if (u in cut_nodes) != (v in cut_nodes):
                usage = edge_n_used[u, v] + edge_n_used[v, u]
                penalty = 0.3 * edge_distance[u, v] * (1 + np.log1p(usage))
                updated[u, v] += penalty
                updated[v, u] += penalty

    return updated
